import{c as e,Q as a,j as p,m as o}from"./chunks/framework.hhGiamYR.js";const d=JSON.parse('{"title":"论纷纷的事情，以及他已","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/upper/39-论纷纷的事情，以及他已.md","filePath":"research/machiavelli/machiavelli/diplomatic/upper/39-论纷纷的事情，以及他已.md"}'),r={name:"research/machiavelli/machiavelli/diplomatic/upper/39-论纷纷的事情，以及他已.md"};function t(c,i,l,_,n,s){return a(),p("div",null,[...i[0]||(i[0]=[o('<h1 id="论纷纷的事情-以及他已" tabindex="-1">论纷纷的事情，以及他已 <a class="header-anchor" href="#论纷纷的事情-以及他已" aria-label="Permalink to &quot;论纷纷的事情，以及他已&quot;">​</a></h1><p>论纷纷的事情，以及他已经给予并正试图给予教皇和瓦伦蒂诺公爵的种种 恩惠给他造成的危害；此二人大肆侵夺他人的产业，四处发动战争蹂躏国 土，造成无尽的罪恶和祸害，辱没国王的赫赫威名，却仍在国王的纵容姑 息之下。二人过去所干的种种罪恶行径同他们最近在博洛尼亚干的事情相 比简直小巫见大巫，同样是在国王陛下的纵容下。国王陛下听闻此事后， 通过信件回复了他们，以使威尼斯人能更为仔细地阅读，更好地了解国王 的意图。”公爵为我读完信的全部内容；事实上，他为所有那些被指控的 罪行进行了辩护，然后，他决定要使所有教会的领地都臣服于他； 一旦威 尼斯人胆敢起来反抗教皇陛下，他们一定会被当成国王陛下的敌人。读完 这封信后，他对我说： “我对你说过许多次，今天晚上我还要再对你说一 次，我们从来就没缺少过支持；法国长矛兵指日可待，另外还有步兵也将 到来，我筹划此事已有些时日了，你也看到我在这里每天都在为此筹集军 饷，教皇不会眼睁睁看着我缺钱，而国王不会让我缺军队。无论在行动上 还是在言语上，我都不愿意虚张声势，而一旦我的敌人胆敢铤而走险，他 们一定会为他们对我所做的一切追悔莫及。”然后，我们将话题转到奥尔 西尼家族上，他说： “他们最近做了一件背信弃义的事情，是他们对我所 犯下的背叛行径中最严重的一次，你知道，就像我前几天对你说的，他们 写信告诉我，他们遵照我的命令要来乌尔比诺公国，此事通过那位奥尔西 诺家族的骑士捎信通知了他们。我相信了他们，因为如同我告诉过你的， 他们进行了卡利要塞的围困战，我写信给唐乌戈，要他率军进入乌尔比 诺，因为奥尔西尼家族的人马会在另一个方向上支援我，他这么做了。但 如果不是他在路上停下来摧毁两座小城堡，我的人马可能就已经被歼灭。 当那支部队准备前进的时候，突然遭到大量当地人的袭击，他们同奥尔西 尼家族的人沆瀣一气，策划了这个阴谋，而后者本应该是我的盟友。他们 现在退到了法诺地区，只携带了一些维持基本需要的物资，假称是我的盟 友。我的另一个类似的盟友詹保罗①,想要进入法诺境内，但未成功。因 ①詹保罗 · 巴廖尼( Giampaolo/Giampagolo Baglioni), 佩鲁贾的领主。——中译者注</p><p>Opere complete di Niccolo Machiavelli</p><p>此,你看看他们有什么办法来应对;他们与我保持着合约关系,并给我写 了非常友好的信件。今天,帕格罗(保罗)大人要到这里来见我,明天, 枢机主教^{\\textcircled}1 要来这里;他们以这种方式来嘲讽我。另一方面,我洗耳恭听 这一切,等待着属于我的时机。通过回答你代表执政团向我提出的那个问 题,我越来越愿意接受他们所有的理由,因为我认识到那才是建立在事实 之上的。我对他们所做的事情非常满意,甚于对我自己,还有他们写的信 中提到已经向锡耶纳派出使节,此事千真万确,因为我已经另外得到消 息;因此,我希望你能够代表我向他们表示,我愿意尽我所能为他们效 力。在你刚来这里的时候,我并没有非常开诚布公地同你说话,因为我的 属国还处于相当危险的境地,听闻乌尔比诺反叛,而我却不知道可以依靠 什么人,我发现在这些新邦国一切都处于混乱无序的状态;我也不想让你 们那些大人相信是巨大的恐惧使我成为只会讲大话的许诺者。但是,我现 在没有那么害怕了,我可以给你更多的承诺;如果需要的话,在我的承 诺之上还要加上我的行为,这样我就不用再担心什么了。”听完他的这段 话,正如我在上面给你们看的,我非常得体地回答了公爵,之后,他又将 话题转到了奥尔西尼家族和条约的谈判。我觉得对他说出发自我内心的话 是合适的,我说: “公爵阁下已看到我们杰出的大人在同你交往时表现得 多么宽宏大量;在处于危险至极的境地时,派我来向你传达他们的友好情 谊,并让你对他们放心,他们不在乎听到什么而改变,无论公爵阁下的威 名日渐高升,还是你的敌人逐渐走向没落;你看到他们已经同你的那些敌 人彻底断绝了一切往来和谈;为了公爵阁下的便利,他们还开启了各条通 道和全部国境,那些事情都值得高度评价,并应该记在心上;因此,我提 醒公爵阁下,在你同奥尔西尼家族或者其他什么人进行和约谈判的时候, 应顾及执政团表现出的友好情谊,所签署的和约不得包含任何与此相悖的 内容,而使用阁下一直以来友好善意的言辞。”公爵阁下回答道: “你们</p><p>\\textcircled1 詹巴蒂斯塔·奥尔西尼( Giambattista Orsini) 。——贝尔泰利编校本注</p><p>不用担心此事。你知道，安东尼奥 ·达 · 韦纳弗罗大人已经代表奥尔西尼 家族来到我这里，在他告诉我的众多其他消息中，他向我提出了变更佛罗 伦萨政府的建议。我对此回答说： ‘佛罗伦萨政府是法国国王的盟友，我 一直是其忠实的仆人，这个政府从未对我造成过伤害；此外，我还在考虑 与他们结盟。’安东尼奥对此的回答是： ‘不要与任何势力结盟，让我 回去后，我们缔结一个更为有利的协定。&#39;为了不给他任何借口，我说： ‘我们已经走到今天的地步，不能再走回头路了；然而，我愿意再对你说 一遍，我愿意听取你的想法，并继续同你谈判，但永远不会同你们缔结有 悖于佛罗伦萨利益的协定，除非该共和国给我某种机会去做此事。’”公 爵继续对我说： “只要这位安东尼奥大人一回去，我向你保证，我就会把 他说的关于你们事务的话全盘透露给你，我将说到做到。”就这样我们结 束了这次谈话，还有许多主题，都无关紧要，不再赘述，于是我离开了公 爵阁下。 诸位大人知道了公爵所说的话，我写的还不到一半；你们现在要考虑 说这些话的人，并以你们惯常的睿智英明来做出判断。关于这里的情况， 自从我到这里之后，公爵阁下的内政外交一直毫无例外地交上了好运；之 所以这样是基于这样一个坚定信念，即法国国王会为他提供军队，教皇会 为他出钱。他事事顺风的另一个同样不可忽视的原因是，他的敌人在给他 施加压力的时候，总是行动迟缓。我个人认为，就目前的情况来看，他们 再也无力对他造成什么损害了，因为他已经在所有重要的地区部署了步 兵，城堡要塞严阵以待；因此，公爵凭借这些措施极大地震慑了敌人的斗 志，他可以安全从容地等待救援的军队。所有由内部势力控制的这些城镇 一旦做出任何异乎寻常的行动，公爵都会让随后到来的法国部队打击他 们；因此，仅是这样的担心就能让他们老老实实，即使不是全部，至少也 是他们中的大部分。 鉴于佩萨罗越来越受到公爵怀疑，他派唐米凯莱带着他其余的人马前 往该城；他对法诺则充满信心，于是就将该城留给其居民自行管理；公爵</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>已经并一直对里米尼疑虑重重，因此，他向该城派出重兵把守；而他对切 塞纳、法恩扎和弗利则没有太多担忧，这是因为弗利人对那位女领主①充 满敌意，而其他两个城市没有领主；公爵本人就在伊莫拉，经受得住来自 博洛尼亚方面的种种动乱。如此一来，公爵将局势稳住，只要请求来自法 国的援兵开赴战场就可以了；拉法埃洛 ·德伊 · 帕齐今天回来了，根据他 的说法，他们现在应该到了费拉拉公国境内，他还说，在距离此地30英里 的××②留下了800名加斯科涅士兵。公爵下令在那里招募的600费拉拉步 兵今天已经到了这里；他今天还派出了米兰多拉领主的秘书带着钱和命令 去招募兵马，并且这位领主也向他保证，将带着自己的人马在10天内前来 效力。另一方面，敌人已经从一侧包围了法诺；并且今天传来消息，他们 已经开始围城；在另一个方向，博洛尼亚军队已经到了圣皮耶罗城堡，他 们在乡村洗劫、焚毁了两天，还有消息称，他们今天晚上就可能到达距此 仅3英里的多奇亚。现在，所有这些情况都要仰赖诸位大人的英明睿智去 判断，并做出最合宜的决策。 鉴于诸位大人已经派出一位大使③前往罗马，我长久停留在这里显得 多余；因此，我恳请诸位大人允许我卸任，因为我的私人事务已经到了崩 溃的边缘，而且我已经花完了你们给我的所有钱款，正如跟随到这里的仆 人都知道的。</p><p>发自伊莫拉，1502年10月23日 仆尼科洛 · 马基雅维利</p><p>附注：今天是24日，据称保罗 · 奥尔西尼大人今晚将到达切塞纳过 夜，明天将到达此地，利用这个机会同公爵阁下会谈。</p><p>① 卡泰丽娜 ·斯福尔扎( Caterina Sforza Riario), 伊莫拉和弗利的女伯爵。 中译者注 ②原文此处空白。 — — 贝尔泰利编校本注 ③焦万 ·维托里奥 ·索德里尼( Giovan Vittorio Soderini)。 中译者注</p><p>信件14</p><p>杰出的诸位大人： 我23日的信保留到24日才发出，为了回复诸位大人21日的信，并让你 们了解我在这里身边所发生的一切。昨天，也就是25日，保罗 · 奥尔西尼 大人装扮成一名信使到达这里，并面见了公爵阁下；据说为了保障他的安 全，枢机主教博尔贾①作为人质交到了奥尔西尼家族手里。保罗大人的到 来在很大程度上是由公爵阁下引起的；在公爵的召唤下，他前来此地为发 生的事情辩护和申诉，并探听公爵的意愿，将这些情况告诉或写信通知其 他人。当天，也就是26日，他派出一名信使前往法诺，以了解其他那些人 最后的决议。我尚无法知道他们会谈的具体内容；我也不认为我可以得到 什么情报，因为公爵阁下最近变得非常谨慎，只同很少几位亲信商谈。 一 项和约一度在谈判，乔瓦尼大人②派出了好几位信使去见埃尔纳主教③; 但如今，随着保罗大人的到来，他常常接见身处圣皮耶罗城堡的安尼巴莱 大人④派出的一位秘书，博洛尼亚人3天前夺取的所有战利品悉数奉还。奥 尔西尼家族的人也没有如同先前传闻的那样围困法诺，本蒂沃利奥家族的 人也没有如这里传闻的那样开赴多奇亚，我昨天在信中是按照这里传闻写 的，所以，没有骚动。我们看到进行和约谈判对公爵十分有利，他也非常 愿意这么做；然而，我还是不要去判断他自己到底怎么想的。 今天是27日，昨天晚上4点，我收到诸位大人发自25日的信，所以， 今天一大早，公爵阁下一起床，我就去见他，我觉得非常有必要将诸位大 人的信的内容同他进行沟通，我为他念了信的大部分。按照他的惯例，公 爵感谢诸位大人的坚定信念，以及通过比诺 ·德 ·罗西大人的到来所做的 沟通，他保证他只能相信你们的意愿，因为他非常赞同你们所说的话和所</p><p>①卢多维科 · 博尔贾( P.Ludovico Borgia) 。——贝尔泰利编校本注 ②乔瓦尼 ·本蒂沃利奥。——贝尔泰利编校本注 ③弗朗切斯科 · 德 · 洛里斯( Francisco de Loris) 。——贝尔泰利编校本注 ④安尼巴莱 · 本蒂沃利奥( Annibale Bentivoglio) 。——贝尔泰利编校本注</p><p>马基雅维利全集 Opere complete di Niccolo Machiavelli</p><p>写的内容。然而，他开始谈论保罗大人的到来以及和约的谈判，他说： “这些人想要的不过是我为他们提供安全。现在，只剩下去找到某种方 式的和约，这应该按照某些确定的条款，他们指望奥尔西尼枢机主教去 做。”还没等我插话，公爵接着说，“对你来说，只要了解这个条约的主 旨精神就够了，我绝不会签署有悖于你们执政团利益的任何条款，我也不 会允许执政团的利益受到丝毫侵犯。”他似乎愿意看到，我们向罗马派出 大使，但就这个事情他并未明确提出来，而是略过去了。 有关萨尔维斯特罗 ·德 ·布奥西，我没有忘记提到此人，完全遵照诸 位大人嘱托我的那些话。公爵阁下回答我说： “你们执政团希望我释放执 政团的这位朋友；我的回答是，我的所有臣民都是执政团的朋友和仆人， 你们应该热爱我的大多数臣民，远甚于只是要求我释放萨尔维斯特罗这一 个人，这会给我们造成灾难；目前，他没有受到任何伤害，这就足够了； 只要我能在不惹怒我的百姓的情况下释放他，我非常乐意地按照执政团的 愿望去做。” 诸位大人在信中希望我再次对你们讲述这里的情况，尤其是具体细 节；关于此事，我已经在上一封信中详细告知了，我估计你们会在24日收 到那封信，我就不再赘述了。这里的情况发展正如我在信中告诉你们的； 除了博洛尼亚人所劫掠的战利品归还了，并且法诺和多奇亚都未遭到围 困，如前所述。确实，今天传来消息说，原先被公爵控制的福松布罗内城 堡被维泰洛佐的人占领了；保罗大人表达了他对此事的不满，对造成此结 果的那些人说了非常严厉的话。还有，关于和约的条款，也许他们之间已 经达成了一致，如果不想对此做没有把握的猜测的话，具体情况仍不得而 知。如果考察一下双方的特性，无论这一方还是那一方，就可以知道公爵 阁下是一个精力充沛而又福星高照的人，充满希望又得到教皇和一位国王 的支持，他发现自己受到攻击，不仅来自一个他想要夺取的邦国，而且来 自一个他已经夺取了的邦国。另一方则被看作是担心他们自己的邦国，并 在他们对公爵造成伤害前就已经对他畏之如虎；现在，在对他造成这样的</p><p>政务与外交著作 Legazioni,commissarie,scritti di governo</p><p>伤害后，他们变得更加恐惧；他们也看不出公爵会如何行事，是原谅这种 伤害，还是让他们一直陷于这种恐惧之中。因此，双方的任何一方都不会 在争夺博洛尼亚和乌尔比诺公国的战事中做出让步。只有在一种情况下双 方才可能达成某种形式的和约，那就是双方愿意联合起来对方第三方，这 样一来，无论是公爵还是联盟都不用缩减各自的力量，而是每一方都会增 加他们的声名和利益。 然而，这样的和约要成为现实，除了对抗佛罗伦萨执政团或威尼斯人 之外，他们无法找到其他势力作为共同的敌人。就你们自身而言，发动对 佛罗伦萨执政团的战事被认为轻而易举，但考虑到法国国王，就没那么容 易了；对威尼斯人发动战事考虑到法国国王则是容易的，但就威尼斯人自 身而言，却绝非易事。对于公爵阁下而言，比较容易接受后一种安排，而 对于联盟而言，前一种安排比较可取；目前，人们相信双方仍未采纳任何 一种方案，而只是在谈论一种可能的构想；所以，目前我也找不到有什么 人知道如何决定他们之间缔结和约的最终方案。不过，那些对谈判具有一 定决定权的人相信，公爵阁下将在联盟成员之间合纵连横，使他们四分五 裂，这样一来，他就不再惧怕他们，进而能够追求自己的利益。我本人更 倾向于相信，这种说法出自他的某些重臣之口，借着坊间舆论流露出口 风。此外，我还得知本蒂沃利奥家族的人对保罗 · 奥尔西尼大人的此次来 访忧心忡忡；然而，这个联盟新近才成立，还没那么容易解体。现在，诸 位大人已经了解这里发生的事情了，鉴于诸位大人更为谨慎睿智和见多识 广，一定能够做出更英明的决策；而我认为自己更适合将所见所闻写信报 告给诸位大人。 相当数量的加斯科涅人来到了博洛尼亚境内的卡斯泰洛城，法国大军 的前方部队不日也将会聚此地。 我再次请求诸位大人准许我卸任，因为公共利益容不得拖延，如果要 决定什么事情，需要派遣具有更高权位的人来处理。我家中的私人事务正 进一步恶化，况且，我在这里没有经费，无法负担日常花销，也实在无法</p><p>继续待下去。向诸位大人致意。</p><p>1502年10月27日，发自伊莫拉 仆尼科洛 · 马基雅维利，国务秘书</p><p>信件15</p><p>杰出的诸位大人： 在上一封写于27日的信中，我向诸位大人报告了这里发生的事情。在 那之后，保罗 · 奥尔西尼大人去了博洛尼亚，今晚又回来了，有公开的消 息称，联盟与公爵之间已经达成和约，目前只等奥尔西尼枢机主教的同 意，就可以正式签署。有关于这份和约的具体条款，我还无法掌握令人满 意的信息，因为据说公爵同乔瓦尼大人、维泰利家族和奥尔西尼家族签署 的所有旧的和约都要被这份新的和约取代，而且，公爵还要重新统一乌尔 比诺公国，并由费拉拉公爵为双方担保。这里还有关于其他事情的传言， 我就不提了，因为大多是无稽之谈。这份和约是否真的已经签署，或者它 是否按照上述方式签署，我不敢妄下结论，因为除了进行有关和约的谈 判外，我看到公爵阁下同时也在花费大量军费，积极备战。就在昨天晚 上，他还派遣阿尔科拉诺大人，带着几千达克特前往伦巴第，以催促其余 的法国部队赶紧来此地；另外还有他在萨伏依将军的儿子①旗下招募的骑 兵部队，我在好几天前的信中提到过此人。除此之外，我还听说，公爵的 重臣高官背后说了许多关于奥尔西尼家族的坏话，称他们是叛徒；今天早 上，我同阿加皮托大人谈起了签约的事，他付之一笑，说进行和约谈判纯 粹是为了拖住他们的缓兵之计。公爵的言谈举止，总是让我得出这样的结</p><p>①前面(信件7)是说米兰将军的儿子，曾任萨伏伊将军。—中译者注</p><p>Legazioni,commissarie,scritti di governo</p>',24)])])}const h=e(r,[["render",t]]);export{d as __pageData,h as default};
